public boolean twoTwo(int[] nums)
{
    for(int i = 0; i < nums.length - 1; i++)
    {
        if(nums[i] == 2)
        {
            if(nums[i + 1] != 2)
            {
                return false;
            }
            i++; // Skip the next number as it is part of the pair
        }
    }
    return true;
}

